const lastTick = global.get("modbus_last_tick") || 0;
const now = Date.now();
const timeout = 1000;

let sendData = {};

// 情况1：从未收到过任何数据（完全没连上）
if (lastTick === 0) {
    sendData = {
        type: "modbusStatus",
        connected: false,
        msg: "未建立Modbus连接，无任何数据返回",
        color: "orange",
        lastTime: "--"
    };
}
// 情况2：3秒内有数据，在线
else if (now - lastTick < timeout) {
    sendData = {
        type: "modbusStatus",
        connected: true,
        msg: "通讯正常",
        color: "green",
        lastTime: new Date(lastTick).toLocaleString()
    };
}
// 情况3：超过3秒无新数据，设备断开（flex-getter无输出）
else {
    sendData = {
        type: "modbusStatus",
        connected: false,
        msg: "Modbus通讯中断，设备无应答",
        color: "red",
        lastTime: new Date(lastTick).toLocaleString()
    };
}

msg.sendData = sendData;
return msg;
